mapper.select:
SELECT s.id,s.category_id,s.scenic_name,s.description,s.cover_image,s.location,s.longitude,s.latitude,s.open_time,s.price,s.score,s.stock,s.is_real_name,s.status,s.view_count,s.create_time,s.update_time,s.is_deleted,c.category_name FROM scenic_spot s LEFT JOIN scenic_category c ON s.category_id = c.id
s.is_deleted = 0
AND s.scenic_name LIKE CONCAT('%', #{keyword}, '%')
AND s.category_id = #{categoryId}
AND s.status = #{status}
ORDER BY s.create_time DESC
